select 
from cases c
left join dict_case_types dct on dct.code = c.type_code
left join users cu on cu.id = c.creator_id
left join users u on u.id = c.handling_officer_id
left join departments dep on dep.id = c.department_id


        and c.case_number like concat('%', #{caseNumber}, '%')


        and c.title like concat('%', #{title}, '%')


        and c.type_code = #{typeCode}


        and c.status = #{status}


        and c.department_id = #{departmentId}


        and c.handling_officer_id = #{handlingOfficerId}


        and c.is_overdue = #{isOverdue}


order by c.id desc
limit #{offset}, #{size}

