insert into case_evidences (
    case_id, file_name, file_path, file_type, file_size, upload_user_id, description, uploaded_at
) values (
    #{caseId}, #{fileName}, #{filePath}, #{fileType}, #{fileSize}, #{uploadUserId}, #{description}, #{uploadedAt}
)

mapper.select:
select ce.*, u.name as upload_user_name
from case_evidences ce
left join users u on u.id = ce.upload_user_id
where ce.id = #{evidenceId}
  and ce.case_id = #{caseId}
